import numpy as npimport reimport statsmodels.api as smimport pandas as pdimport nltkfrom nltk.sentiment import SentimentIntensityAnalyzerdfText=pd.read_table("data/out.txt")fh=open("data/out.txt",mode="r")content=fh.read()contentlist=content.split("SECRET")contentlist[1]# lav til dataframecontenDf=pd.DataFrame(data=contentlist,columns=["text"])# FE: chunksizecontenDf['size']=contenDf['text'].apply(lambda x: len(x))contenDf['dates']=contenDf['text'].apply(lambda x: re.findall(" [0-9]{1,2} [a-zA-Z]+ 19[0-9]{2} ",x))contenDf['ldate']=contenDf['dates'].apply(lambda x: len(x))# subset chunks with interesting datescontenDfDates=contenDf.query('ldate > 0')sa=SentimentIntensityAnalyzer()sa.sentiment_val